-- Source files are combined from supabase/migrations in filename order.

-- ============================================================
-- 20260621023000_initial_schema.sql
-- ============================================================
-- CoupleSync initial Supabase schema.
-- Run this once in Supabase SQL Editor or through the Supabase CLI.

create extension if not exists pgcrypto;

create table public.profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  display_name text not null default '',
  avatar_url text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.couples (
  id uuid primary key default gen_random_uuid(),
  name text not null default 'Our Calendar',
  invite_code text not null unique default lower(encode(gen_random_bytes(5), 'hex')),
  created_by uuid not null references auth.users(id) on delete cascade,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.couple_members (
  couple_id uuid not null references public.couples(id) on delete cascade,
  user_id uuid not null references auth.users(id) on delete cascade,
  role text check (role in ('him', 'her')),
  joined_at timestamptz not null default now(),
  primary key (couple_id, user_id)
);

create unique index couple_members_one_role_per_couple
  on public.couple_members(couple_id, role)
  where role is not null;

create table public.layers (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  slug text,
  name text not null,
  type text not null check (type in ('schedule', 'habits', 'todos', 'custom')),
  owner_role text check (owner_role in ('him', 'her', 'both')),
  color text,
  sort_order integer not null default 0,
  is_system boolean not null default false,
  is_visible_by_default boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create unique index layers_unique_slug_per_couple
  on public.layers(couple_id, slug)
  where slug is not null;

create table public.events (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  layer_id uuid references public.layers(id) on delete set null,
  title text not null,
  event_date date not null,
  start_time time,
  end_time time,
  all_day boolean not null default false,
  owner_role text not null default 'both' check (owner_role in ('him', 'her', 'both')),
  source text not null default 'manual' check (source in ('manual', 'google', 'apple')),
  external_id text,
  notes text,
  created_by uuid references auth.users(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index events_couple_date_idx on public.events(couple_id, event_date);

create table public.habit_definitions (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  name text not null,
  color text not null default '#4ade80',
  owner_role text not null default 'both' check (owner_role in ('him', 'her', 'both')),
  sort_order integer not null default 0,
  is_active boolean not null default true,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table public.habit_logs (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  habit_id uuid not null references public.habit_definitions(id) on delete cascade,
  habit_date date not null,
  owner_role text not null default 'both' check (owner_role in ('him', 'her', 'both')),
  logged_by uuid references auth.users(id) on delete set null,
  note text,
  created_at timestamptz not null default now()
);

create index habit_logs_couple_date_idx on public.habit_logs(couple_id, habit_date);

create unique index habit_logs_one_per_role_date
  on public.habit_logs(couple_id, habit_id, habit_date, owner_role);

create table public.todos (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  text text not null,
  completed boolean not null default false,
  scheduled_date date,
  assignee_role text not null default 'both' check (assignee_role in ('him', 'her', 'both', 'unassigned')),
  source_message_id uuid,
  created_by uuid references auth.users(id) on delete set null,
  completed_by uuid references auth.users(id) on delete set null,
  completed_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index todos_couple_scheduled_date_idx on public.todos(couple_id, scheduled_date);

create table public.inbox_messages (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  parent_id uuid references public.inbox_messages(id) on delete cascade,
  sender_id uuid references auth.users(id) on delete set null,
  sender_role text not null default 'him' check (sender_role in ('him', 'her')),
  category text not null default 'idea' check (category in ('idea', 'plan', 'love')),
  content text not null,
  converted_event_id uuid references public.events(id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index inbox_messages_couple_parent_idx on public.inbox_messages(couple_id, parent_id);

alter table public.todos
  add constraint todos_source_message_fk
  foreign key (source_message_id)
  references public.inbox_messages(id)
  on delete set null;

create table public.calendar_connections (
  id uuid primary key default gen_random_uuid(),
  couple_id uuid not null references public.couples(id) on delete cascade,
  user_id uuid not null references auth.users(id) on delete cascade,
  provider text not null check (provider in ('google', 'apple')),
  provider_account_id text,
  scopes text[] not null default '{}',
  token_reference text,
  sync_cursor text,
  expires_at timestamptz,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (user_id, provider, provider_account_id)
);

create or replace function public.touch_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

create trigger profiles_touch_updated_at
  before update on public.profiles
  for each row execute function public.touch_updated_at();

create trigger couples_touch_updated_at
  before update on public.couples
  for each row execute function public.touch_updated_at();

create trigger layers_touch_updated_at
  before update on public.layers
  for each row execute function public.touch_updated_at();

create trigger events_touch_updated_at
  before update on public.events
  for each row execute function public.touch_updated_at();

create trigger habit_definitions_touch_updated_at
  before update on public.habit_definitions
  for each row execute function public.touch_updated_at();

create trigger todos_touch_updated_at
  before update on public.todos
  for each row execute function public.touch_updated_at();

create trigger inbox_messages_touch_updated_at
  before update on public.inbox_messages
  for each row execute function public.touch_updated_at();

create trigger calendar_connections_touch_updated_at
  before update on public.calendar_connections
  for each row execute function public.touch_updated_at();

create or replace function public.is_couple_member(target_couple_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select auth.uid() is not null
    and exists (
      select 1
      from public.couple_members
      where couple_id = target_couple_id
        and user_id = auth.uid()
    );
$$;

create or replace function public.seed_couple_defaults()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into public.layers (couple_id, slug, name, type, owner_role, color, sort_order, is_system)
  values
    (new.id, 'him_schedule', 'His Schedule', 'schedule', 'him', '#d1e6e0', 10, true),
    (new.id, 'her_schedule', 'Her Schedule', 'schedule', 'her', '#f0e6eb', 20, true),
    (new.id, 'shared_habits', 'Shared Habits', 'habits', 'both', '#e0e5ed', 30, true),
    (new.id, 'todos', 'To-Dos', 'todos', 'both', '#d8dadc', 40, true);

  insert into public.habit_definitions (couple_id, name, color, owner_role, sort_order)
  values
    (new.id, 'Vocabulary', '#4ade80', 'both', 10),
    (new.id, 'Shower', '#d8dadc', 'both', 20),
    (new.id, 'Exercise', '#a65d5d', 'both', 30);

  return new;
end;
$$;

create trigger couples_seed_defaults
  after insert on public.couples
  for each row execute function public.seed_couple_defaults();

create or replace function public.create_couple_workspace(
  p_name text default 'Our Calendar',
  p_role text default null
)
returns table (couple_id uuid, invite_code text)
language plpgsql
security definer
set search_path = public
as $$
declare
  new_couple public.couples%rowtype;
begin
  if auth.uid() is null then
    raise exception 'not_authenticated';
  end if;

  if p_role is not null and p_role not in ('him', 'her') then
    raise exception 'invalid_role';
  end if;

  insert into public.couples (name, created_by)
  values (coalesce(nullif(trim(p_name), ''), 'Our Calendar'), auth.uid())
  returning * into new_couple;

  insert into public.couple_members (couple_id, user_id, role)
  values (new_couple.id, auth.uid(), p_role);

  return query
    select new_couple.id, new_couple.invite_code;
end;
$$;

create or replace function public.join_couple_by_invite_code(
  p_invite_code text,
  p_role text default null
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  target_couple_id uuid;
  normalized_code text;
begin
  if auth.uid() is null then
    raise exception 'not_authenticated';
  end if;

  if p_role is not null and p_role not in ('him', 'her') then
    raise exception 'invalid_role';
  end if;

  normalized_code := lower(trim(p_invite_code));

  select id
  into target_couple_id
  from public.couples
  where invite_code = normalized_code;

  if target_couple_id is null then
    raise exception 'invite_code_not_found';
  end if;

  insert into public.couple_members (couple_id, user_id, role)
  values (target_couple_id, auth.uid(), p_role)
  on conflict (couple_id, user_id)
  do update set role = coalesce(excluded.role, public.couple_members.role);

  return target_couple_id;
end;
$$;

