  with check (public.is_couple_member(id));

create policy "members can view couple membership"
  on public.couple_members
  for select
  to authenticated
  using (user_id = auth.uid() or public.is_couple_member(couple_id));

create policy "creators and members can add themselves"
  on public.couple_members
  for insert
  to authenticated
  with check (
    user_id = auth.uid()
    and (
      public.is_couple_member(couple_id)
      or exists (
        select 1
        from public.couples
        where id = couple_id
          and created_by = auth.uid()
      )
    )
  );

